Node* copyRandomList(Node* head) {
    if (!head) return nullptr;
    unordered_map<Node*, Node*> seen;
    Node* curr = head;
    while (curr) {
        seen[curr] = new Node(curr->val);
        curr = curr->next;
    }
    curr = head;
    while (curr) {
        seen[curr]->next = seen[curr->next];
        seen[curr]->random = seen[curr->random];
        curr = curr->next;
    }
    return seen[head];
}
